		QueryRoot root = optimizeBeforeSketch(new Distinct(new LeftJoin(pattern, pattern.clone())));

		Distinct distinct = assertInstanceOf(Distinct.class, root.getArg(), () -> root.toString());
		assertInstanceOf(StatementPattern.class, distinct.getArg(), () -> root.toString());
